import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentUsage {
  usage: number;
  unit: string;
  cost: number;
  currency: string;
}

interface DailyCost {
  day: string;
  cost: number;
}

interface EnergyUsageData {
  currentUsage: CurrentUsage;
  dailyCost: DailyCost[];
  usageTrend: number[];
}

export default function Widget() {
  const energyUsageData = response.data as EnergyUsageData;
  const { currentUsage, dailyCost, usageTrend } = energyUsageData;
  const clipPathId = `clip-path-${response.widget.id}`;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Energy Usage
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {currentUsage.usage} {currentUsage.unit}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FFC107' }}>
              Cost: {currentUsage.currency} {currentUsage.cost.toFixed(2)}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 160 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: usageTrend,
                  color: '#FFC107',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: dailyCost.map((d, i) => d.day),
                  scaleType: 'band',
                },
              ]}
              yAxis={[{ id: 'usage', position: 'left' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="usage"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={1}>
            {dailyCost.slice(0, 5).map((cost) => (
              <Box key={cost.day}>
                <Typography variant="caption" color="text.secondary">
                  {cost.day}
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {currentUsage.currency} {cost.cost.toFixed(2)}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
